bool
licmOnLoop(Loop* L, DominatorTree& DT, LoopInfo& LI)
{
  bool changed = false;

  // Build preheader if needed.  We create one only if there's exactly one
  // "outside" predecessor of the header.
  auto header = L->getHeader();
  BasicBlock* preheader = L->getLoopPreheader();
  if (!preheader)
    return false; // skip irregular loops

  // Recurse into subloops first.
  for (auto sub : L->getSubLoops())
    changed |= licmOnLoop(sub, DT, LI);

  std::vector<Instruction*> toHoist;
  for (auto* bb : L->blocks()) {
    // Skip subloops to avoid double-hoisting (only consider blocks directly
    // owned by this loop).
    if (LI.getLoopFor(bb) != L)
      continue;
    for (auto& I : *bb) {
      if (!isSafeToHoist(I))
        continue;
      // Loads: only if no store inside the loop writes their ptr.
      if (auto li = dyn_cast<LoadInst>(&I)) {
        if (!isLoopInvariantValue(li->getPointerOperand(), L))
          continue;
        if (loopWritesToPtr(L, li->getPointerOperand()))
          continue;
        toHoist.push_back(&I);
        continue;
      }
      // Other safe insts: all operands invariant?
      bool ok = true;
      for (Value* op : I.operands()) {
        if (!isLoopInvariantValue(op, L)) {
          ok = false;
          break;
        }
      }
      if (ok)
        toHoist.push_back(&I);
    }
  }

  // Hoist them in order (so dependencies are satisfied).
  auto insertPt = preheader->getTerminator();
  for (auto* I : toHoist) {
    I->moveBefore(insertPt);
    changed = true;
  }
  return changed;
}

action.new_str:
bool
licmOnLoop(Loop* L, DominatorTree& DT, LoopInfo& LI)
{
  bool changed = false;

  // Build preheader if needed.  We create one only if there's exactly one
  // "outside" predecessor of the header.
  auto header = L->getHeader();
  BasicBlock* preheader = L->getLoopPreheader();
  if (!preheader)
    return false; // skip irregular loops

  // Recurse into subloops first.
  for (auto sub : L->getSubLoops())
    changed |= licmOnLoop(sub, DT, LI);

  std::vector<Instruction*> toHoist;
  for (auto* bb : L->blocks()) {
    // Skip subloops to avoid double-hoisting (only consider blocks directly
    // owned by this loop).
    if (LI.getLoopFor(bb) != L)
      continue;
    for (auto& I : *bb) {
      if (!isSafeToHoist(I))
        continue;
      // Loads: only if no store inside the loop writes their ptr.
      if (auto li = dyn_cast<LoadInst>(&I)) {
        if (!isLoopInvariantValue(li->getPointerOperand(), L))
          continue;
        if (loopWritesToPtr(L, li->getPointerOperand()))
          continue;
        toHoist.push_back(&I);
        continue;
      }
      // Other safe insts: all operands invariant?
      bool ok = true;
      for (Value* op : I.operands()) {
        if (!isLoopInvariantValue(op, L)) {
          ok = false;
          break;
        }
      }
      if (ok)
        toHoist.push_back(&I);
    }
  }

  // Hoist them in order (so dependencies are satisfied).
  auto insertPt = preheader->getTerminator();
  for (auto* I : toHoist) {
    I->moveBefore(insertPt);
    changed = true;
  }

  // -----------------------------------------------------------------
  // Store-LICM: hoist `store v, p` where:
  //   - v and p are loop-invariant
  //   - p is backed by a local alloca (so the store has no externally
  //     observable side effect besides the local memory)
  //   - inside the loop, p is the target of EXACTLY ONE store (this one)
  //     (so the value at p is constant across iterations)
  //   - the loop has no calls (potential aliasing with arbitrary memory)
  //
  // We delete the in-loop store and emit an equivalent store at the end of
  // the preheader.
  // -----------------------------------------------------------------
  std::vector<StoreInst*> storesToHoist;
  // First, check if the loop has any calls — if so, abort store-LICM.
  bool hasCall = false;
  for (auto* bb : L->blocks()) {
    if (LI.getLoopFor(bb) != L)
      continue;
    for (auto& I : *bb) {
      if (isa<CallBase>(I)) {
        hasCall = true;
        break;
      }
    }
    if (hasCall)
      break;
  }
  if (!hasCall) {
    // Count stores per pointer.
    std::unordered_map<Value*, unsigned> storeCount;
    for (auto* bb : L->blocks()) {
      if (LI.getLoopFor(bb) != L)
        continue;
      for (auto& I : *bb) {
        if (auto si = dyn_cast<StoreInst>(&I)) {
          storeCount[si->getPointerOperand()]++;
        }
      }
    }
    for (auto* bb : L->blocks()) {
      if (LI.getLoopFor(bb) != L)
        continue;
      for (auto& I : *bb) {
        auto si = dyn_cast<StoreInst>(&I);
        if (!si)
          continue;
        Value* ptr = si->getPointerOperand();
        Value* val = si->getValueOperand();
        if (!isLoopInvariantValue(ptr, L))
          continue;
        if (!isLoopInvariantValue(val, L))
          continue;
        if (!isLocalAllocaBacked(ptr))
          continue;
        if (storeCount[ptr] != 1)
          continue;
        storesToHoist.push_back(si);
      }
    }
    for (auto* si : storesToHoist) {
      // Move the store to the end of the preheader.
      si->moveBefore(insertPt);
      changed = true;
    }
  }

  return changed;
}

